pub const TokenCat = enum(u8) {
    @"ident",
    @"token",
    @"string",
    @"integer",
    @"eq",
    @"pipe",
    @"arrow",
    @"larrow",
    @"question",
    @"star",
    @"plus",
    @"lparen",
    @"rparen",
    @"lbracket",
    @"rbracket",
    @"langle",
    @"rangle",
    @"lbrace",
    @"rbrace",
    @"comma",
    @"colon",
